// ─── Types ───────────────────────────────────────────────────────────────────

type Filter = "all" | "industrial" | "land";

interface Asset {
  title: string;
  image: string;
  type: string;
  city: string;
  area: string;
}

interface StateData {
  id: string;
  name: string;
  count: number;
  /** SVG viewBox coords (0 0 553 608) */
  markerX: number;
  markerY: number;
  x: number; // UI Column placement X coordinate
  y: number;
  /** which side list the connector line goes to */
  connector: "left" | "right";
  filter: Filter[];
  assets: Asset[];
}

