const LEFT_STATES = STATES.filter((s) => s.connector === "left");
const RIGHT_STATES = STATES.filter((s) => s.connector === "right");
const DESKTOP_LAYOUT_WIDTH = 1200;
const DESKTOP_LAYOUT_HEIGHT = 650;

// ─── Sub-components ──────────────────────────────────────────────────────────

function FilterTabs({
  active,
  onChange,
}: {
  active: Filter;
  onChange: (f: Filter) => void;
}) {
  const tabs: { key: Filter; label: string }[] = [
    { key: "all", label: "All Assets" },
    { key: "industrial", label: "Industrial & Logistics Parks" },
    { key: "land", label: "Land Parcels" },
  ];
  return (
    <div className="flex items-center gap-[10px] flex-wrap justify-center">
      {tabs.map((t) => (
        <button
          key={t.key}
          onClick={() => onChange(t.key)}
          className={`px-4 py-1.5  text-[14px] tracking-[-0.14px] font-medium border transition-all duration-200 ${
            active === t.key
              ? "bg-[#FF6F69] text-white border-[#FF6F69]"
              : "bg-white text-[#222] border-gray-200 hover:border-gray-400"
          }`}
        >
          {t.label}
        </button>
      ))}
    </div>
  );
}

function StateMarker({
  x,
  y,
  active,
  onClick,
}: {
  x: number;
  y: number;
  active: boolean;
  onClick: () => void;
}) {
  return (
    <g
      transform={`translate(${x},${y})`}
      onClick={onClick}
      style={{ cursor: "pointer" }}
      role="button"
      aria-label="state marker"
    >
      {/* Outer pulse ring */}
      {active && (
        <motion.circle
          r={14}
          fill="none"
          stroke="#FF6F69"
          strokeWidth={1.5}
          strokeOpacity={0.4}
          initial={{ r: 10, opacity: 0.6 }}
          animate={{ r: 18, opacity: 0 }}
          transition={{ duration: 1.2, repeat: Infinity, ease: "easeOut" }}
        />
      )}
      {/* Outer white ring */}
      <motion.circle
        r={active ? 10 : 8}
        fill="white"
        filter="url(#markerShadow)"
        animate={{ r: active ? 10 : 8 }}
        transition={{ duration: 0.25 }}
      />
      {/* Middle coral ring */}
      <motion.circle
        r={active ? 6 : 5}
        fill="#FF6F69"
        animate={{ r: active ? 6 : 5 }}
        transition={{ duration: 0.25 }}
      />
      {/* Center dot */}
      <circle r={2} fill="white" />
    </g>
  );
}

interface AssetData {
  image: string;
  title: string;
  type: string;
  city: string;
  area: string;
}

interface StateData {
  id: string;
  count: number;
  name: string;
  assets: AssetData[];
}

